"""FastAPI routing module — APIRouter and route registration."""
from __future__ import annotations

import asyncio
import functools
from typing import Any, Callable, Dict, List, Optional, Sequence, Set, Type, Union

from starlette.routing import Route, Router
from starlette.requests import Request
from starlette.responses import JSONResponse, Response
from starlette.types import ASGIApp


class APIRoute:
    """A single route registered in the APIRouter."""

    def __init__(
        self,
        path: str,
        endpoint: Callable,
        *,
        response_model: Optional[Type[Any]] = None,
        status_code: int = 200,
        tags: Optional[List[str]] = None,
        summary: Optional[str] = None,
        description: Optional[str] = None,
        response_description: str = "Successful Response",
        responses: Optional[Dict[Union[int, str], Dict[str, Any]]] = None,
        deprecated: Optional[bool] = None,
        name: Optional[str] = None,
        methods: Optional[Union[Set[str], List[str]]] = None,
        operation_id: Optional[str] = None,
        include_in_schema: bool = True,
        response_class: Type[Response] = JSONResponse,
    ) -> None:
        self.path = path
        self.endpoint = endpoint
        self.response_model = response_model
        self.status_code = status_code
        self.tags = tags or []
        self.summary = summary
        self.description = description or endpoint.__doc__ or ""
        self.responses = responses or {}
        self.deprecated = deprecated
        self.name = name or endpoint.__name__
        self.methods = {m.upper() for m in (methods or [])}
        self.operation_id = operation_id
        self.include_in_schema = include_in_schema
        self.response_class = response_class

    async def handle(self, scope: dict, receive: Any, send: Any) -> None:
        request = Request(scope, receive, send)
        response = await self._run_endpoint(request)
        await response(scope, receive, send)

    async def _run_endpoint(self, request: Request) -> Response:
        if asyncio.iscoroutinefunction(self.endpoint):
            result = await self.endpoint()
        else:
            result = await asyncio.get_event_loop().run_in_executor(None, self.endpoint)
        return self.response_class(content=result, status_code=self.status_code)


class APIRouter(Router):
    """
    APIRouter — groups related routes and includes them in FastAPI app.

    Usage::

        router = APIRouter()

        @router.get("/users")
        def list_users():
            return []

        app.include_router(router, prefix="/api")
    """

    def __init__(
        self,
        *,
        routes: Optional[List[Any]] = None,
        redirect_slashes: bool = True,
        default: Optional[ASGIApp] = None,
        dependency_overrides_provider: Optional[Any] = None,
        route_class: Type[APIRoute] = APIRoute,
        default_response_class: Type[Response] = JSONResponse,
        prefix: str = "",
        tags: Optional[List[str]] = None,
        dependencies: Optional[Sequence[Any]] = None,
        responses: Optional[Dict[Union[int, str], Dict[str, Any]]] = None,
    ) -> None:
        super().__init__(routes=routes or [], redirect_slashes=redirect_slashes, default=default)
        self.dependency_overrides_provider = dependency_overrides_provider
        self.route_class = route_class
        self.default_response_class = default_response_class
        self.tags = tags or []
        self.dependencies = list(dependencies or [])
        self.responses = responses or {}
        self.prefix = prefix

    def add_api_route(self, path: str, endpoint: Callable, *, methods: List[str], **kwargs: Any) -> None:
        route = self.route_class(path=path, endpoint=endpoint, methods=methods, **kwargs)
        self.routes.append(route)

    def get(self, path: str, **kwargs: Any) -> Callable:
        def decorator(func: Callable) -> Callable:
            self.add_api_route(path, func, methods=["GET"], **kwargs)
            return func
        return decorator

    def post(self, path: str, **kwargs: Any) -> Callable:
        def decorator(func: Callable) -> Callable:
            self.add_api_route(path, func, methods=["POST"], **kwargs)
            return func
        return decorator

    def put(self, path: str, **kwargs: Any) -> Callable:
        def decorator(func: Callable) -> Callable:
            self.add_api_route(path, func, methods=["PUT"], **kwargs)
            return func
        return decorator

    def delete(self, path: str, **kwargs: Any) -> Callable:
        def decorator(func: Callable) -> Callable:
            self.add_api_route(path, func, methods=["DELETE"], **kwargs)
            return func
        return decorator

    def include_router(self, router: "APIRouter", *, prefix: str = "", tags: Optional[List[str]] = None, **kwargs: Any) -> None:
        for route in router.routes:
            if hasattr(route, "path"):
                route.path = prefix + route.path
            self.routes.append(route)
